/**
 * generate-redirect-test-matrix.mjs
 *
 * Builds a redirect validation matrix from the crawl export generated by
 * `scripts/crawl-seo.mjs`, then probes the target host path-by-path.
 *
 * Usage:
 *   node scripts/generate-redirect-test-matrix.mjs
 *   node scripts/generate-redirect-test-matrix.mjs --target=https://devlo-agency.ch
 *
 * Output:
 *   reports/seo-migration/redirect-test-matrix-YYYY-MM-DD.csv
 *   reports/seo-migration/redirect-test-matrix-YYYY-MM-DD-summary.md
 */

import { mkdirSync, readFileSync, writeFileSync } from "node:fs";

const args = Object.fromEntries(
  process.argv.slice(2).map((arg) => {
    const [k, v] = arg.split("=");
    return [k.replace(/^--/, ""), v ?? "true"];
  }),
);

const TARGET_ORIGIN = (args.target ?? "https://devlo-agency.ch").replace(/\/+$/, "");
const INPUT_CSV = "seo-crawl-exports/URL_MAPPING_DEVLO_MIGRATION_from_crawl.csv";
const OUTPUT_DIR = "reports/seo-migration";
const DATE = new Date().toISOString().slice(0, 10);
const OUTPUT_CSV = `${OUTPUT_DIR}/redirect-test-matrix-${DATE}.csv`;
const OUTPUT_SUMMARY = `${OUTPUT_DIR}/redirect-test-matrix-${DATE}-summary.md`;
const MAX_HOPS = 10;
const CONCURRENCY = 8;
const USER_AGENT = "Devlo-Redirect-Matrix/1.0 (+https://devlo-agency.ch)";

function parseCsvLine(line) {
  const cells = [];
  let current = "";
  let inQuotes = false;

  for (let i = 0; i < line.length; i += 1) {
    const ch = line[i];

    if (ch === "\"") {
      const next = line[i + 1];
      if (inQuotes && next === "\"") {
        current += "\"";
        i += 1;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }

    if (ch === "," && !inQuotes) {
      cells.push(current);
      current = "";
      continue;
    }

    current += ch;
  }

  cells.push(current);
  return cells;
}

function parseCsvRows(text) {
  const rows = [];
  let row = [];
  let current = "";
  let inQuotes = false;

  for (let i = 0; i < text.length; i += 1) {
    const ch = text[i];
    const next = text[i + 1];

    if (ch === "\"") {
      if (inQuotes && next === "\"") {
        current += "\"";
        i += 1;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }

    if (ch === "," && !inQuotes) {
      row.push(current);
      current = "";
      continue;
    }

    if ((ch === "\n" || ch === "\r") && !inQuotes) {
      if (ch === "\r" && next === "\n") i += 1;
      row.push(current);
      current = "";
      if (row.some((cell) => cell.length > 0)) rows.push(row);
      row = [];
      continue;
    }

    current += ch;
  }

  if (current.length > 0 || row.length > 0) {
    row.push(current);
    if (row.some((cell) => cell.length > 0)) rows.push(row);
  }

  return rows;
}

function parseCsv(text) {
  const rows = parseCsvRows(text);
  const [headers, ...dataRows] = rows;
  return dataRows.map((values) => {
    const row = {};
    headers.forEach((header, i) => {
      row[header] = values[i] ?? "";
    });
    return row;
  });
}

function csvCell(value) {
  const stringValue = String(value ?? "");
  return `"${stringValue.replaceAll("\"", "\"\"")}"`;
}

async function fetchHop(url) {
  const res = await fetch(url, {
    method: "GET",
    redirect: "manual",
    headers: { "user-agent": USER_AGENT },
  });

  try {
    await res.body?.cancel();
  } catch {
    // no-op
  }

  return {
    status: res.status,
    location: res.headers.get("location") ?? "",
  };
}

async function inspectChain(startUrl) {
  const hops = [];
  let currentUrl = startUrl;

  for (let i = 0; i < MAX_HOPS; i += 1) {
    const hop = await fetchHop(currentUrl);
    hops.push({ url: currentUrl, ...hop });

    if (hop.status < 300 || hop.status >= 400 || !hop.location) {
      break;
    }

    currentUrl = new URL(hop.location, currentUrl).toString();
  }

  return hops;
}

function classifyResult(path, hops) {
  const first = hops[0];
  const last = hops[hops.length - 1];
  const finalHost = (() => {
    try {
      return new URL(last.url).host;
    } catch {
      return "";
    }
  })();
  const finalPath = (() => {
    try {
      const u = new URL(last.url);
      return `${u.pathname}${u.search}`;
    } catch {
      return "";
    }
  })();

  const redirectStatuses = new Set([301, 302, 307, 308]);
  const firstIsRedirect = redirectStatuses.has(first.status);
  const finalOk = last.status >= 200 && last.status < 300;
  const onTargetHost = finalHost === new URL(TARGET_ORIGIN).host;
  const hasChain = hops.length > 2;

  let verdict = "REVIEW";
  if (firstIsRedirect && first.location && finalOk && onTargetHost && !hasChain) {
    verdict = "PASS_REDIRECT";
  } else if (!firstIsRedirect && finalOk && onTargetHost) {
    verdict = "PASS_OK";
  } else if (hasChain && finalOk && onTargetHost) {
    verdict = "WARN_CHAIN";
  } else if (last.status === 404) {
    verdict = "FAIL_404";
  } else if (last.status >= 500) {
    verdict = "FAIL_5XX";
  }

  // Special note for catch-all redirects to homepage that may be intentional.
  const note = finalPath === "/" && path !== "/" ? "Redirects to homepage (verify intent)" : "";

  return { finalHost, finalPath, verdict, note, hasChain };
}

function normalizePathFromOldUrl(oldUrl) {
  try {
    const u = new URL(oldUrl);
    return `${u.pathname}${u.search}`;
  } catch {
    return "";
  }
}

async function main() {
  mkdirSync(OUTPUT_DIR, { recursive: true });

  const rows = parseCsv(readFileSync(INPUT_CSV, "utf8"));
  const queue = rows.map((row) => ({
    oldUrl: row.old_url,
    sourceStatusCode: row.status_code,
    priority: row.priority,
    source: row.source,
    title: row.title,
    crawlNote: row.note,
    path: normalizePathFromOldUrl(row.old_url),
  }));

  const results = [];
  let cursor = 0;

  async function worker() {
    while (cursor < queue.length) {
      const index = cursor;
      cursor += 1;
      const item = queue[index];

      const testUrl = `${TARGET_ORIGIN}${item.path || "/"}`;
      let hops;
      let error = "";

      try {
        hops = await inspectChain(testUrl);
      } catch (err) {
        error = err instanceof Error ? err.message : String(err);
        hops = [{ url: testUrl, status: 0, location: "" }];
      }

      const first = hops[0];
      const last = hops[hops.length - 1];
      const classification = classifyResult(item.path || "/", hops);

      results[index] = {
        ...item,
        testUrl,
        firstHopStatus: first.status,
        firstHopLocation: first.location,
        hopCount: hops.length - 1,
        finalStatus: last.status,
        finalUrl: last.url,
        finalHost: classification.finalHost,
        finalPath: classification.finalPath,
        chainDetected: classification.hasChain ? "yes" : "no",
        verdict: error ? "ERROR" : classification.verdict,
        note: [item.crawlNote, classification.note, error].filter(Boolean).join(" | "),
      };

      process.stdout.write(
        `\rProcessed ${index + 1}/${queue.length} (${results.filter(Boolean).length} done)`,
      );
    }
  }

  await Promise.all(Array.from({ length: CONCURRENCY }, () => worker()));
  process.stdout.write("\n");

  const columns = [
    ["old_url", "oldUrl"],
    ["source_status_code", "sourceStatusCode"],
    ["priority", "priority"],
    ["source", "source"],
    ["title", "title"],
    ["path", "path"],
    ["test_url", "testUrl"],
    ["first_hop_status", "firstHopStatus"],
    ["first_hop_location", "firstHopLocation"],
    ["hop_count", "hopCount"],
    ["final_status", "finalStatus"],
    ["final_url", "finalUrl"],
    ["final_host", "finalHost"],
    ["final_path", "finalPath"],
    ["chain_detected", "chainDetected"],
    ["verdict", "verdict"],
    ["note", "note"],
  ];

  const csvLines = [
    columns.map(([header]) => header).join(","),
    ...results.map((row) => columns.map(([, key]) => csvCell(row[key])).join(",")),
  ];
  writeFileSync(OUTPUT_CSV, `${csvLines.join("\n")}\n`, "utf8");

  const counts = results.reduce((acc, row) => {
    acc.total += 1;
    acc[row.verdict] = (acc[row.verdict] ?? 0) + 1;
    return acc;
  }, { total: 0 });

  const sampleFails = results
    .filter((row) => !String(row.verdict).startsWith("PASS"))
    .slice(0, 20)
    .map(
      (row) =>
        `- ${row.path} -> status ${row.firstHopStatus}, location ${row.firstHopLocation || "(none)"}, final ${row.finalStatus} ${row.finalPath}`,
    );

  const summary = [
    `# Redirect Test Matrix Summary (${DATE})`,
    "",
    `- Target host tested: \`${TARGET_ORIGIN}\``,
    `- Source file: \`${INPUT_CSV}\``,
    `- Total URLs tested: **${counts.total}**`,
    `- PASS_REDIRECT: **${counts.PASS_REDIRECT ?? 0}**`,
    `- PASS_OK: **${counts.PASS_OK ?? 0}**`,
    `- WARN_CHAIN: **${counts.WARN_CHAIN ?? 0}**`,
    `- FAIL_404: **${counts.FAIL_404 ?? 0}**`,
    `- FAIL_5XX: **${counts.FAIL_5XX ?? 0}**`,
    `- ERROR: **${counts.ERROR ?? 0}**`,
    `- REVIEW: **${counts.REVIEW ?? 0}**`,
    "",
    "## Non-pass samples",
    ...(sampleFails.length > 0 ? sampleFails : ["- None"]),
    "",
  ].join("\n");

  writeFileSync(OUTPUT_SUMMARY, summary, "utf8");

  console.log(`\nWrote: ${OUTPUT_CSV}`);
  console.log(`Wrote: ${OUTPUT_SUMMARY}`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
